function extractJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('TVPX__30: empty prompt-spec output.');

  const candidates = [
    text,
    text.replace(/```json\s*/gi, '').replace(/```/g, '').trim(),
  ];

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[“”]/g, '"')
      .replace(/[‘’]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');
    return JSON.parse(slice);
  }

  throw new Error('TVPX__30: could not parse prompt-spec JSON.');
}

function cleanText(v) {
  return String(v || '')
    .replace(/\s+/g, ' ')
    .replace(/\s+([,.;:!?])/g, '$1')
    .trim();
}

function wordCount(v) {
  const text = cleanText(v);
  return text ? text.split(/\s+/).length : 0;
}

function clipWords(v, max) {
  const text = cleanText(v);
  const parts = text.split(/\s+/);
  return parts.length <= max ? text : parts.slice(0, max).join(' ');
}

function normalizeNegative(v) {
  const defaults = [
    'cgi',
    '3d render',
    'illustration',
    'cartoon',
    'plastic skin',
    'waxy skin',
    'beauty retouching',
    'bad hands',
    'extra fingers',
    'duplicate limbs',
    'deformed anatomy',
    'watermark',
    'logo',
  ];

  const incoming = String(v || '')
    .split(',')
    .map((part) => cleanText(part).toLowerCase())
    .filter(Boolean);
  const uniq = [...new Set(incoming)];
  return (uniq.length ? uniq : defaults).join(', ');
}

