const base = $items('Select Winning Candidate')[0]?.json || {};
const critic = base.render_critic || base.vision_critic || {};
const imageUrl = String(render.image_url || '').trim();
if (!imageUrl) throw new Error('TVPX__30: B/W render returned no image_url.');

return [{
  json: {
    ctx: base.ctx,
    concept_id: String(base.scene_seed_id || '').trim(),
    scene_seed_id: String(base.scene_seed_id || '').trim(),
    scene_blueprint_id: String(base.scene_blueprint_id || '').trim(),
    archetype_id: String(base.archetype_id || '').trim(),
    render_candidate_id: String(render.render_candidate_id || '').trim(),
    blueprint_label: String(base.blueprint_label || '').trim(),
    reference_alignment_score: Number(critic.reference_alignment_score || 0),
    critic_overall_score: Number(critic.overall_score || 0),
    asset_family_id: String(base.ctx?.asset_family_id || '').trim() || null,
    asset_id: String(render.render_candidate_id || '').trim() ? `tvpx_as_${render.render_candidate_id}_bw` : null,
    family: {
      bw: {
        image_url: imageUrl,
        provider_image_url: imageUrl,
        provider_name: String(render.provider_name || '').trim(),
        provider_job_id: String(render.provider_job_id || '').trim(),
        prompt_final: String(render.prompt_final || '').trim(),
        negative_prompt_raw: String(render.negative_prompt_raw || '').trim(),
        output_format: String(render.output_format || 'png').trim(),
        render_candidate_id: String(render.render_candidate_id || '').trim(),
      },
    },
  },
}];

const locked = $items('Verify Lock Ownership')[0]?.json || {};
const winner = $items('Select Winning Candidate')[0]?.json || {};

const ctx = locked.ctx || winner.ctx || {};
const sceneSeedId = String(locked.scene_seed_id || winner.scene_seed_id || '').trim();
const usedCount = Number(locked.scene_seed_row?.used_count || winner.scene_seed_row?.used_count || 0);

if (!sceneSeedId) throw new Error('TVPX__30: missing scene_seed_id for final scene-seed release.');
if (!String(ctx.trace_id || '').trim()) throw new Error('TVPX__30: missing trace_id for final scene-seed release.');

return [{
  json: {
    ctx,
    scene_seed_id: sceneSeedId,
    used_count_next: usedCount + 1,
  },
}];
